           JSON.stringify(aiReview.ai_missing_fields),
           JSON.stringify(aiReview.ai_suggested_actions),
           aiReview.ai_confidence,
           aiReview.ai_adjustment,
           aiReview.ai_mode,
           finalScore,
           finalLevel
